import{_ as s,o as e,c as i,a2 as n}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"Secret、最小权限与费用上限","description":"","frontmatter":{"type":"ai-note","stage":"beginner","topic":"secrets-permissions-cost","verified":"2026-07-17T00:00:00.000Z","tags":["ai","security","secrets","least-privilege","cost"]},"headers":[],"relativePath":"04-ai/notes/00-foundations/secrets-permissions-cost.md","filePath":"04-ai/notes/00-foundations/secrets-permissions-cost.md","lastUpdated":null}'),t={name:"04-ai/notes/00-foundations/secrets-permissions-cost.md"};function l(r,a,h,p,o,d){return e(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="secret、最小权限与费用上限" tabindex="-1">Secret、最小权限与费用上限 <a class="header-anchor" href="#secret、最小权限与费用上限" aria-label="Permalink to &quot;Secret、最小权限与费用上限&quot;">​</a></h1><h2 id="_1-概念、用途与工程边界" tabindex="-1">1. 概念、用途与工程边界 <a class="header-anchor" href="#_1-概念、用途与工程边界" aria-label="Permalink to &quot;1. 概念、用途与工程边界&quot;">​</a></h2><h3 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h3><p>Secret 是能够授予系统访问能力的敏感值，包括 API Key、访问 Token、密码、私钥和连接串。最小权限要求身份只获得完成当前任务所需的最少资源、操作和时间范围。费用上限通过账户预算、项目配额、速率限制、请求限制和应用内计量控制模型调用的财务风险。</p><h3 id="为什么需要" tabindex="-1">为什么需要 <a class="header-anchor" href="#为什么需要" aria-label="Permalink to &quot;为什么需要&quot;">​</a></h3><p>模型 API 通常按输入、输出或工具使用计费。Secret 泄露会导致未授权访问、数据暴露和费用损失；Agent 或循环代码即使没有攻击者也可能因失控重试和长上下文快速增加费用。</p><h3 id="核心特性" tabindex="-1">核心特性 <a class="header-anchor" href="#核心特性" aria-label="Permalink to &quot;核心特性&quot;">​</a></h3><h3 id="secret-生命周期" tabindex="-1">Secret 生命周期 <a class="header-anchor" href="#secret-生命周期" aria-label="Permalink to &quot;Secret 生命周期&quot;">​</a></h3><p>Secret 需要创建、分发、存储、使用、轮换、吊销和审计。长期静态 Key 风险高于短期凭据。Secret 不应出现在源代码、Git、URL、客户端包、截图、日志和模型上下文中。</p><h3 id="最小权限" tabindex="-1">最小权限 <a class="header-anchor" href="#最小权限" aria-label="Permalink to &quot;最小权限&quot;">​</a></h3><p>开发、测试、CI 和生产使用不同身份。只读与写入权限分开；不同项目和租户分开；能够限制模型、区域或预算时应显式限制。高风险操作需要服务端再次授权，不能相信模型生成的参数。</p><h3 id="费用边界" tabindex="-1">费用边界 <a class="header-anchor" href="#费用边界" aria-label="Permalink to &quot;费用边界&quot;">​</a></h3><p>控制分为多层：供应商账户预算与告警、项目级配额、用户/租户速率限制、单请求最大输入输出、Agent 最大步骤和总超时、队列并发、异常检测与熔断。告警不是硬限制，必须确认供应商预算功能是否会自动停止请求。</p><h3 id="工程使用" tabindex="-1">工程使用 <a class="header-anchor" href="#工程使用" aria-label="Permalink to &quot;工程使用&quot;">​</a></h3><p>上线前检查：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[ ] Secret 由服务端 Secret Manager 或受控运行环境提供</span></span>
<span class="line"><span>[ ] 本地 Secret 文件已忽略，仓库启用 Secret 扫描</span></span>
<span class="line"><span>[ ] 开发、CI、生产使用不同凭据</span></span>
<span class="line"><span>[ ] Key 可立即吊销和轮换</span></span>
<span class="line"><span>[ ] 日志和错误报告会脱敏</span></span>
<span class="line"><span>[ ] 设置账户预算、项目告警和应用硬上限</span></span>
<span class="line"><span>[ ] 每请求限制输入、输出、重试、步骤和总时间</span></span>
<span class="line"><span>[ ] Usage 按用户、租户、模型、功能和版本记录</span></span>
<span class="line"><span>[ ] 费用异常能够停止队列或关闭功能</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>发生泄露时先吊销/轮换，不要先花时间清理 Git 历史。随后确认使用日志、影响范围和下游凭据，再清理历史并补检测规则。</p><h3 id="常见错误与边界" tabindex="-1">常见错误与边界 <a class="header-anchor" href="#常见错误与边界" aria-label="Permalink to &quot;常见错误与边界&quot;">​</a></h3><ul><li>把 Secret 放入 <code>.env</code> 后认为绝对安全；<code>.env</code> 只是本地配置方式，仍可能被误提交、备份或读取。</li><li>在浏览器调用模型供应商并暴露长期 Key。</li><li>只设费用告警，不设应用级最大 Token、步骤、并发和速率。</li><li>多租户共享高权限凭据且不记录租户 Usage，无法归责和隔离。</li><li>把 Tool 输出和外部文档当可信指令，导致模型诱导高成本或高权限调用。</li></ul><h3 id="延伸机制" tabindex="-1">延伸机制 <a class="header-anchor" href="#延伸机制" aria-label="Permalink to &quot;延伸机制&quot;">​</a></h3><p>费用治理也影响可靠性：限制过严会造成正常请求失败，因此应区分硬上限、软告警和降级策略。可以在达到阈值后切换低成本模型、减少上下文、禁用非必要 Tool 或转人工处理，但必须记录质量影响。</p><h2 id="三类控制的执行位置" tabindex="-1">三类控制的执行位置 <a class="header-anchor" href="#三类控制的执行位置" aria-label="Permalink to &quot;三类控制的执行位置&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;用户请求&quot;] --&gt; B[&quot;应用认证与授权&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[&quot;预算、速率、步骤上限&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[&quot;服务端持有 Secret 调用模型&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[&quot;Tool 参数再次授权&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[&quot;审计与 Usage 结算&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>Prompt 可以提示模型不要执行高风险操作，但授权、硬预算和业务不变量必须由受控系统执行。供应商“预算”可能只是告警，是否能阻断请求必须按具体产品验证。</p><h2 id="生命周期与控制明细" tabindex="-1">生命周期与控制明细 <a class="header-anchor" href="#生命周期与控制明细" aria-label="Permalink to &quot;生命周期与控制明细&quot;">​</a></h2><table tabindex="0"><thead><tr><th>对象</th><th>创建/使用</th><th>失败响应</th></tr></thead><tbody><tr><td>Secret</td><td>受控生成、最小范围、服务端注入</td><td>泄露后吊销、轮换、审计</td></tr><tr><td>权限</td><td>每个请求基于当前身份和资源检查</td><td>默认拒绝，不由模型补全</td></tr><tr><td>费用</td><td>预估预留，完成后按 Usage 结算</td><td>降级、排队、停止或人工审批</td></tr><tr><td>Agent 步骤</td><td>最大步数、总时长、工具白名单</td><td>保存状态并返回明确原因</td></tr></tbody></table><h2 id="可验证实例" tabindex="-1">可验证实例 <a class="header-anchor" href="#可验证实例" aria-label="Permalink to &quot;可验证实例&quot;">​</a></h2><p>假设租户每日硬预算 10 元，当前已用 9.20 元，请求按最大输入输出估算上限 1.50 元。系统应在调用前拒绝或请求额外授权，而不是先调用再等待账单。若实际 Usage 仅 0.40 元，结算后释放预留差额；并发请求必须原子预留，避免共同越过预算。</p><h2 id="验证与排错" tabindex="-1">验证与排错 <a class="header-anchor" href="#验证与排错" aria-label="Permalink to &quot;验证与排错&quot;">​</a></h2><ol><li>在测试环境使用无生产权限的独立凭据。</li><li>用 Secret 扫描器检查仓库、构建产物和日志样本。</li><li>注入 401、403、预算不足和重复 Tool 请求，确认不会自动放宽权限。</li><li>对循环任务验证最大 Token、步骤、并发、时长和费用均能终止任务。</li></ol><h2 id="练习与完成标准" tabindex="-1">练习与完成标准 <a class="header-anchor" href="#练习与完成标准" aria-label="Permalink to &quot;练习与完成标准&quot;">​</a></h2><p>设计一个模型调用网关的安全清单。验收：凭据不进入客户端；开发/生产隔离；按租户授权；调用前预留预算、调用后结算；有硬停止条件；泄露演练能在不修改代码的情况下吊销凭据。</p><h2 id="完整案例-多租户摘要服务" tabindex="-1">完整案例：多租户摘要服务 <a class="header-anchor" href="#完整案例-多租户摘要服务" aria-label="Permalink to &quot;完整案例：多租户摘要服务&quot;">​</a></h2><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><ul><li>租户 A 与 B 使用同一应用，但文档和预算相互隔离。</li><li>每个租户每日硬预算 100 元，单请求最大预留 2 元。</li><li>模型 Key 仅后端可读；文档 Tool 需要当前用户身份与资源授权。</li></ul><h3 id="逐步处理" tabindex="-1">逐步处理 <a class="header-anchor" href="#逐步处理" aria-label="Permalink to &quot;逐步处理&quot;">​</a></h3><ol><li>网关验证用户会话并解析租户，不接受请求体自行声明的租户作为授权事实。</li><li>事务性检查租户剩余预算并预留 2 元；预留失败则不调用模型。</li><li>后端通过受控 Secret 引用调用模型，日志只记录凭据版本，不记录值。</li><li>每次 Tool 调用重新检查用户对文档的读取权限，模型生成的文档 ID 只是不可信参数。</li><li>响应完成后依据 Usage 与价格版本计算实际费用，结算并释放差额。</li><li>任务取消、超时或流中断仍写计量状态；无法获得最终 Usage 时标记待对账，而非假定零费用。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;tenant&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;tenant-a-hash&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;reservation&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;actual_cost&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.43</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;released&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.57</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;credential_version&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;model-prod-7&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;authorization&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;allowed&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>使用租户 A 身份请求租户 B 文档，必须在 Tool 执行前拒绝。</li><li>并发发送足以超过剩余预算的请求，只有事务性预留范围内的请求获准。</li><li>将 Key 放入测试日志，Secret 扫描器必须阻断流水线。</li><li>轮换凭据后旧版本立即不可用，应用无需重新构建。</li></ul><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>若供应商控制台预算仅发送邮件告警，应用仍可能继续消费。硬停止必须由已验证能阻断的供应商配额或应用网关执行。若日志包含完整 Prompt，还需单独评估其中的个人数据和商业秘密；隐藏 Key 不等于日志安全。</p><h2 id="边界检查矩阵" tabindex="-1">边界检查矩阵 <a class="header-anchor" href="#边界检查矩阵" aria-label="Permalink to &quot;边界检查矩阵&quot;">​</a></h2><ol><li>Secret 创建后记录所有者、用途、范围和到期时间。</li><li>分发使用受控引用，不通过聊天、工单和源代码传值。</li><li>运行时只向需要的进程提供，不传给模型上下文。</li><li>轮换同时更新消费者并验证旧值失效。</li><li>授权每次基于当前身份、资源和动作重新检查。</li><li>Tool 参数来自模型时仍是不可信输入。</li><li>租户隔离在数据库查询和缓存键中同时执行。</li><li>费用预留使用最坏请求上限并处理并发竞争。</li><li>最终 Usage 按价格版本结算，异常请求进入对账。</li><li>Agent 设置步数、Token、时间、工具和费用多重上限。</li><li>告警提供可见性，硬限制负责停止。</li><li>事件日志脱敏且访问受限，支持泄露调查。</li></ol><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://cheatsheetseries.owasp.org/cheatsheets/Secrets_Management_Cheat_Sheet.html" target="_blank" rel="noreferrer">OWASP Secrets Management Cheat Sheet</a>（访问日期：2026-07-17）</li><li><a href="https://cheatsheetseries.owasp.org/cheatsheets/Authorization_Cheat_Sheet.html" target="_blank" rel="noreferrer">OWASP Authorization Cheat Sheet</a>（访问日期：2026-07-17）</li><li><a href="https://cheatsheetseries.owasp.org/cheatsheets/Logging_Cheat_Sheet.html" target="_blank" rel="noreferrer">OWASP Logging Cheat Sheet</a>（访问日期：2026-07-17）</li></ul>`,47)])])}const k=s(t,[["render",l]]);export{u as __pageData,k as default};
